{
  "name": "todo-cli",
  "version": "1.0.0",
  "description": "A simple CLI for managing a todo list",
  "main": "dist/cli.js",
  "scripts": {
    "start": "node dist/cli.js",
    "build": "tsc"
  },
  "author": "",
  "license": "ISC"
}

declare const require: any;
const { randomUUID: uuidv4 } = require("node:crypto"); // import { randomUUID as uuidv4  } from 'node:crypto'
const fs = require("node:fs");
const path = require("node:path");

export class Task {
  id: string;
  title: string;
  done: boolean;
  createdAt: string;
  doneAt?: string;

  constructor(title: string) {
    this.id = uuidv4();
    this.title = title;
    this.done = false;
    this.createdAt = new Date().toISOString();
  }
}

export class TaskStore {
  filePath: string;

  constructor(filePath: string) {
    this.filePath = filePath;
    if (!fs.existsSync(filePath)) {
      fs.writeFileSync(filePath, JSON.stringify({ tasks: [] }));
    }
  }

  list(): Task[] {
    const data = fs.readFileSync(this.filePath, 'utf8');
    return JSON.parse(data).tasks;
  }

  add(title: string): Task {
    const task = new Task(title);
    const data = fs.readFileSync(this.filePath, 'utf8');
    const tasks = JSON.parse(data).tasks;
    tasks.push(task);
    fs.writeFileSync(this.filePath, JSON.stringify({ tasks: tasks }));
    return task;
  }

  done(id: string): Task {
    const data = fs.readFileSync(this.filePath, 'utf8');
    const tasks = JSON.parse(data).tasks;
    const task = tasks.find(t => t.id === id);
    if (task) {
      task.done = true;
      task.doneAt = new Date().toISOString();
      fs.writeFileSync(this.filePath, JSON.stringify({ tasks: tasks }));
    }
    return task;
  }

  remove(id: string): Task {
    const data = fs.readFileSync(this.filePath, 'utf8');
    const tasks = JSON.parse(data).tasks;
    const taskIndex = tasks.findIndex(t => t.id === id);
    if (taskIndex !== -1) {
      const removedTask = tasks.splice(taskIndex, 1)[0];
      fs.writeFileSync(this.filePath, JSON.stringify({ tasks: tasks }));
      return removedTask;
    }
    return null;
  }
}

declare const process: any;
declare const require: any;
const fs = require("node:fs");
import { TaskStore } from './store';

const argv = process.argv.slice(2);
const cmd = argv[0];
const dataPath = argv.find(arg => arg.startsWith('--data'));
const filePath = dataPath ? dataPath.split('=')[1] : '';

if (!filePath) {
  console.error('--data <path> is required');
  process.exit(1);
}

const store = new TaskStore(filePath);

switch (cmd) {
  case 'list':
    const tasks = store.list();
    console.log(JSON.stringify({ ok: true, tasks: tasks }));
    break;
  case 'add':
    if (argv.length < 2) {
      console.error('Usage: add <title>');
      process.exit(1);
    }
    const title = argv[1];
    const task = store.add(title);
    console.log(JSON.stringify({ ok: true, task: task }));
    break;
  case 'done':
    if (argv.length < 2) {
      console.error('Usage: done <id>');
      process.exit(1);
    }
    const id = argv[1];
    const doneTask = store.done(id);
    if (doneTask) {
      console.log(JSON.stringify({ ok: true, task: doneTask }));
    } else {
      console.log(JSON.stringify({ ok: false, message: 'Task not found' }));
    }
    break;
  case 'remove':
    if (argv.length < 2) {
      console.error('Usage: remove <id>');
      process.exit(1);
    }
    const removeId = argv[1];
    const removedTask = store.remove(removeId);
    if (removedTask) {
      console.log(JSON.stringify({ ok: true, task: removedTask }));
    } else {
      console.log(JSON.stringify({ ok: false, message: 'Task not found' }));
    }
    break;
  default:
    console.error('Unknown command');
    process.exit(1);
}
